SELECT po.order_id, po.supplier_id, po.store_id, po.order_date, po.expected_date, po.status, po.total_amount, po.notes, po.created_by, s.name AS supplier_name, st.name AS store_name FROM purchase_orders po JOIN suppliers s ON po.supplier_id = s.supplier_id JOIN stores st ON po.store_id = st.store_id
AND po.status = #{status} AND po.supplier_id = #{supplierId}
ORDER BY po.order_id DESC OFFSET #{offset} ROWS FETCH NEXT #{limit} ROWS ONLY

SELECT COUNT(*) FROM purchase_orders po

    AND po.status = #{status}
    AND po.supplier_id = #{supplierId}
